/* ── fill() replaces {tokens} in any value (deep) ─── */
function fill(obj, v) {
  if (typeof obj === 'string') {
    return obj.replace(/\{(\w+)\}/g, (_, k) => v[k] ?? _);
  }
  if (Array.isArray(obj)) return obj.map(i => fill(i, v));
  if (obj && typeof obj === 'object') {
    return Object.fromEntries(Object.entries(obj).map(([k, val]) => [k, fill(val, v)]));
  }
  return obj;
}

